function lra_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function lra_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function lra_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function lra_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function lra_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function lra_where($src,&$p){$from=isset($src['tgl_awal'])&&$src['tgl_awal']!==''?$src['tgl_awal']:date('Y-m-01');$to=isset($src['tgl_akhir'])&&$src['tgl_akhir']!==''?$src['tgl_akhir']:date('Y-m-t');$w=" WHERE l.start_date<=? AND l.end_date>=? ";array_push($p,$to,$from);if(isset($src['employee_id'])&&$src['employee_id']!==''){$w.=" AND l.employee_id=? ";$p[]=(int)$src['employee_id'];}if(isset($src['job_title_id'])&&$src['job_title_id']!==''){$w.=" AND l.job_title_id=? ";$p[]=(int)$src['job_title_id'];}foreach(array('department_code','leave_type','workflow_status','decision','approval_level') as $k){if(isset($src[$k])&&$src[$k]!==''){$w.=" AND l.$k=? ";$p[]=$src[$k];}}$impact=isset($src['impact_type'])?$src['impact_type']:'';if($impact==='QUOTA_DEDUCT')$w.=" AND l.leave_quota_before>l.leave_quota_after ";elseif($impact==='PENDING_APPROVAL')$w.=" AND l.workflow_status IN ('SUBMITTED','MANAGER_APPROVED','HR_APPROVED') ";elseif($impact==='APPROVED_USAGE')$w.=" AND l.workflow_status='APPROVED' ";elseif($impact==='EXCEPTION')$w.=" AND l.workflow_status IN ('REJECTED','RETURNED','CANCELLED') ";elseif($impact==='ATTACHMENT')$w.=" AND l.attachment_ref IS NOT NULL AND l.attachment_ref<>'' ";if(isset($src['keyword'])&&$src['keyword']!==''){$kw='%'.$src['keyword'].'%';$w.=" AND (l.leave_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR l.reason LIKE ? OR l.sap_reference LIKE ? OR d.nm_dept LIKE ?) ";for($i=0;$i<6;$i++)$p[]=$kw;}return $w;}
$act=isset($_GET['act'])?$_GET['act']:'';
switch($act){
case 'employee_search':$t=trim(lra_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,employee_no,full_name,department_code,employee_group FROM erp_employee_master WHERE (?='' OR employee_no LIKE ? OR full_name LIKE ? OR department_code LIKE ?) ORDER BY employee_no LIMIT 50",array($t,$like,$like,$like));lra_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name.' ['.$r->department_code.' / '.$r->employee_group.']';});
case 'department_search':$t=trim(lra_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT kd_dept,nm_dept,dept_type FROM dept WHERE (?='' OR kd_dept LIKE ? OR nm_dept LIKE ? OR dept_type LIKE ?) ORDER BY kd_dept LIMIT 50",array($t,$like,$like,$like));lra_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept.' ['.$r->dept_type.']';});
case 'job_title_search':$t=trim(lra_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,job_title_code,job_title_name FROM erp_job_title WHERE (?='' OR job_title_code LIKE ? OR job_title_name LIKE ?) ORDER BY job_title_code LIMIT 50",array($t,$like,$like));lra_select2($rows,'id',function($r){return $r->job_title_code.' - '.$r->job_title_name;});
case 'detail':$r=$db->fetch("SELECT l.*,e.employee_no,e.full_name,e.employee_group,d.nm_dept,j.job_title_code,j.job_title_name,app.employee_no approver_no,app.full_name approver_name,hr.employee_no hr_no,hr.full_name hr_name,hand.employee_no handover_no,hand.full_name handover_name FROM erp_leave_request l JOIN erp_employee_master e ON e.id=l.employee_id LEFT JOIN dept d ON d.kd_dept=l.department_code LEFT JOIN erp_job_title j ON j.id=l.job_title_id LEFT JOIN erp_employee_master app ON app.id=l.approver_employee_id LEFT JOIN erp_employee_master hr ON hr.id=l.hr_reviewer_employee_id LEFT JOIN erp_employee_master hand ON hand.id=l.handover_to_employee_id WHERE l.id=? LIMIT 1",array((int)lra_p('id')));if(!$r){echo '<div class="alert alert-warning">Leave Request tidak ditemukan.</div>';break;}$logs=$db->query("SELECT a.*,e.employee_no,e.full_name FROM erp_leave_approval a LEFT JOIN erp_employee_master e ON e.id=a.approver_employee_id WHERE a.leave_request_id=? ORDER BY a.id",array((int)$r->id));echo '<h3 style="margin-top:0">'.lra_h($r->leave_no).' <small>'.lra_h($r->employee_no.' - '.$r->full_name).'</small></h3><span class="label label-info">'.lra_h($r->leave_type).'</span> <span class="label label-success">'.lra_h($r->workflow_status).'</span> <span class="label label-primary">'.lra_h($r->decision).'</span><hr><div class="row"><div class="col-sm-3"><b>'.hr_h('hr_period', 'Period').'</b><br>'.lra_h($r->start_date.' s/d '.$r->end_date).'</div><div class="col-sm-3"><b>Total Days</b><br>'.number_format((float)$r->total_days,2).'</div><div class="col-sm-3"><b>Quota</b><br>'.lra_h($r->leave_quota_before.' -> '.$r->leave_quota_after).'</div><div class="col-sm-3"><b>Attachment</b><br>'.lra_h($r->attachment_ref?:'-').'</div></div><hr><div class="row"><div class="col-sm-3"><b>'.hr_h('hr_department', 'Department').'</b><br>'.lra_h(($r->department_code?:'-').' - '.($r->nm_dept?:'-')).'</div><div class="col-sm-3"><b>'.hr_h('hr_job_title', 'Job Title').'</b><br>'.lra_h(($r->job_title_code?:'-').' - '.($r->job_title_name?:'-')).'</div><div class="col-sm-3"><b>Approver</b><br>'.lra_h($r->approver_no?($r->approver_no.' - '.$r->approver_name):'-').'</div><div class="col-sm-3"><b>HR Reviewer</b><br>'.lra_h($r->hr_no?($r->hr_no.' - '.$r->hr_name):'-').'</div></div><hr><b>Reason</b><p>'.nl2br(lra_h($r->reason?:'-')).'</p><b>Approver Note</b><p>'.nl2br(lra_h($r->approver_note?:'-')).'</p><h4>Approval History</h4><table class="table table-bordered table-condensed"><tr><th>'.hr_h('common_no', 'No').'</th><th>Step</th><th>Decision</th><th>'.hr_h('common_status', 'Status').'</th><th>Approver</th><th>'.hr_h('hr_date', 'Date').'</th><th>Note</th></tr>';$n=1;foreach($logs as $l){echo '<tr><td>'.$n++.'</td><td>'.lra_h($l->approval_step).'</td><td>'.lra_h($l->decision).'</td><td>'.lra_h($l->previous_status.' -> '.$l->new_status).'</td><td>'.lra_h(trim(($l->employee_no?:'').' '.($l->full_name?:''))?:'-').'</td><td>'.lra_h($l->decision_date?:'-').'</td><td>'.lra_h($l->approval_note?:'-').'</td></tr>';}if($n===1)echo '<tr><td colspan="7" class="text-center text-muted">Belum ada approval history.</td></tr>';echo '</table>';break;
case 'export':$initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$p=array();$w=lra_where($_GET,$p);$rows=$db->query("SELECT l.*,e.employee_no,e.full_name,d.nm_dept,j.job_title_code,j.job_title_name,app.employee_no approver_no,app.full_name approver_name,hr.employee_no hr_no,hr.full_name hr_name,hand.employee_no handover_no,hand.full_name handover_name,(SELECT COUNT(*) FROM erp_leave_approval la WHERE la.leave_request_id=l.id) approval_count FROM erp_leave_request l JOIN erp_employee_master e ON e.id=l.employee_id LEFT JOIN dept d ON d.kd_dept=l.department_code LEFT JOIN erp_job_title j ON j.id=l.job_title_id LEFT JOIN erp_employee_master app ON app.id=l.approver_employee_id LEFT JOIN erp_employee_master hr ON hr.id=l.hr_reviewer_employee_id LEFT JOIN erp_employee_master hand ON hand.id=l.handover_to_employee_id $w ORDER BY l.start_date DESC,l.leave_no DESC",$p);$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Leave Report'));$heads=array(erp_export_label("No"),erp_export_label("Leave No"),erp_export_label("Employee"),erp_export_label("Department"),erp_export_label("Job Title"),erp_export_label("Leave Type"),erp_export_label("Request Date"),erp_export_label("Start Date"),erp_export_label("End Date"),erp_export_label("Half Day"),erp_export_label("Total Days"),erp_export_label("Quota Before"),erp_export_label("Quota After"),erp_export_label("Quota Deducted"),erp_export_label("Workflow Status"),erp_export_label("Approval Level"),erp_export_label("Decision"),erp_export_label("Approver"),erp_export_label("HR Reviewer"),erp_export_label("Handover"),erp_export_label("Decision By"),erp_export_label("Decision At"),erp_export_label("Approval Count"),erp_export_label("Attachment"),erp_export_label("Reason"),erp_export_label("SAP Ref"),erp_export_label("Updated By"));foreach($heads as $i=>$h)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rn=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->leave_no,$r->employee_no.' - '.$r->full_name,($r->department_code?:'').' - '.($r->nm_dept?:''),($r->job_title_code?:'').' - '.($r->job_title_name?:''),$r->leave_type,$r->request_date,$r->start_date,$r->end_date,$r->start_half_day.' / '.$r->end_half_day,(float)$r->total_days,(float)$r->leave_quota_before,(float)$r->leave_quota_after,(float)$r->leave_quota_before-(float)$r->leave_quota_after,$r->workflow_status,$r->approval_level,$r->decision,$r->approver_no.' - '.$r->approver_name,$r->hr_no.' - '.$r->hr_name,$r->handover_no.' - '.$r->handover_name,$r->decision_by,$r->decision_at,$r->approval_count,$r->attachment_ref,$r->reason,$r->sap_reference,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rn,$v);$rn++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('LEAVE REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($heads),'decimal_columns'=>array('K','L','M','N'),'filters'=>array('Period'=>lra_g('tgl_awal',date('Y-m-01')).' s/d '.lra_g('tgl_akhir',date('Y-m-t'))),'widths'=>array('B'=>18,'C'=>30,'D'=>28,'E'=>26,'F'=>20,'R'=>30,'S'=>30,'T'=>30,'Y'=>36)));$tmp=erpkb_excel_temp_file('leave_report_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="leave_report_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
